/**
 * Enhanced Cart Session API
 * 
 * Security Audit Issue #9 Fix: Session Management Weaknesses
 * 
 * Features:
 * - Cryptographically secure session tokens
 * - Idle timeout (1 hour) and session expiration (7 days)
 * - Automatic session rotation for long-lived sessions
 * - Device fingerprinting and validation
 * - IP address tracking
 * - HttpOnly + Secure + SameSite cookies
 */

import type { MedusaRequest, MedusaResponse } from "@medusajs/framework/http"
import { SessionManager } from "../../../services/SessionManager"

// Helper to parse cookies from Cookie header (Medusa doesn't auto-parse cookies)
function parseCookies(cookieHeader?: string): Record<string, string> {
  if (!cookieHeader) return {}

  return cookieHeader.split(';').reduce((cookies, cookie) => {
    const [name, ...rest] = cookie.trim().split('=')
    if (name && rest.length > 0) {
      cookies[name] = rest.join('=')
    }
    return cookies
  }, {} as Record<string, string>)
}

const CART_SESSION_COOKIE = 'cart_session_token'
const CART_SESSION_TTL = 86400 * 7 // 7 days in seconds

// GET - Retrieve current cart session (with validation)
export async function GET(req: MedusaRequest, res: MedusaResponse) {
  try {
    const cookies = parseCookies(req.headers.cookie as string | undefined)
    const sessionToken = cookies[CART_SESSION_COOKIE]

    if (!sessionToken) {
      return res.json({ 
        session: null,
        message: 'No active cart session' 
      })
    }

    // Validate session (checks expiration, idle timeout, fingerprint)
    const validation = await SessionManager.validateSession(req, sessionToken)

    if (!validation.valid) {
      // Clear invalid cookie
      const cookieValue = [
        `${CART_SESSION_COOKIE}=`,
        'HttpOnly',
        process.env.NODE_ENV === 'production' ? 'Secure' : '',
        'SameSite=Lax',
        'Max-Age=0',
        'Path=/'
      ].filter(Boolean).join('; ')

      res.setHeader('Set-Cookie', cookieValue)

      return res.json({ 
        session: null,
        message: `Session ${validation.reason}`,
        reason: validation.reason
      })
    }

    // Check if session needs rotation
    if (validation.requiresRotation) {
      return res.json({ 
        session: {
          cartId: validation.session!.cartId,
          userId: validation.session!.userId,
          createdAt: validation.session!.createdAt,
          lastAccessedAt: validation.session!.lastAccessedAt
        },
        requiresRotation: true,
        message: 'Session valid but rotation recommended'
      })
    }

    return res.json({ 
      session: {
        cartId: validation.session!.cartId,
        userId: validation.session!.userId,
        createdAt: validation.session!.createdAt,
        lastAccessedAt: validation.session!.lastAccessedAt
      },
      message: 'Session retrieved successfully' 
    })

  } catch (error) {
    console.error('[CART_SESSION] GET error:', error)
    return res.status(500).json({ 
      error: 'Failed to retrieve session',
      message: error instanceof Error ? error.message : 'Unknown error'
    })
  }
}

// POST - Create or update cart session
export async function POST(req: MedusaRequest, res: MedusaResponse) {
  try {
    console.log('[CART_SESSION] POST request received', {
      hasBody: !!req.body,
      hasPublishableKey: !!req.headers['x-publishable-api-key']
    })

    const { cartId, userId } = req.body as { cartId?: string; userId?: string }

    if (!cartId) {
      console.error('[CART_SESSION] No cartId in request body')
      return res.status(400).json({ 
        error: 'Cart ID is required' 
      })
    }

    const cookies = parseCookies(req.headers.cookie as string | undefined)
    const existingToken = cookies[CART_SESSION_COOKIE]

    let sessionToken: string
    let sessionData

    // Check if updating existing session
    if (existingToken) {
      const validation = await SessionManager.validateSession(req, existingToken)

      if (validation.valid && validation.session) {
        // Update existing session
        await SessionManager.updateSession(existingToken, { cartId, userId })
        sessionToken = existingToken
        sessionData = validation.session

        console.log('[CART_SESSION] Updated existing session', {
          sessionId: existingToken.substring(0, 12) + '...',
          cartId,
          userId: userId ? userId.substring(0, 8) + '...' : 'guest'
        })
      } else {
        // Session invalid, create new one
        const result = await SessionManager.createSession(req, cartId, userId)
        sessionToken = result.token
        sessionData = result.session
      }
    } else {
      // Create new session
      const result = await SessionManager.createSession(req, cartId, userId)
      sessionToken = result.token
      sessionData = result.session
    }

    // Set httpOnly cookie
    const isProduction = process.env.NODE_ENV === 'production'
    const cookieValue = [
      `${CART_SESSION_COOKIE}=${sessionToken}`,
      'HttpOnly',
      isProduction ? 'Secure' : '',
      'SameSite=Lax',
      `Max-Age=${CART_SESSION_TTL}`,
      'Path=/'
    ].filter(Boolean).join('; ')

    res.setHeader('Set-Cookie', cookieValue)

    return res.json({ 
      success: true,
      sessionId: sessionData.sessionId,
      cartId: sessionData.cartId,
      message: 'Session created/updated successfully'
    })

  } catch (error) {
    console.error('[CART_SESSION] POST error:', error)
    return res.status(500).json({ 
      error: 'Failed to create/update session',
      message: error instanceof Error ? error.message : 'Unknown error'
    })
  }
}

// DELETE - Clear cart session
export async function DELETE(req: MedusaRequest, res: MedusaResponse) {
  try {
    const cookies = parseCookies(req.headers.cookie as string | undefined)
    const sessionToken = cookies[CART_SESSION_COOKIE]

    if (sessionToken) {
      await SessionManager.deleteSession(sessionToken)

      console.log('[CART_SESSION] Session deleted', {
        sessionToken: sessionToken.substring(0, 12) + '...'
      })
    }

    // Clear cookie
    const cookieValue = [
      `${CART_SESSION_COOKIE}=`,
      'HttpOnly',
      process.env.NODE_ENV === 'production' ? 'Secure' : '',
      'SameSite=Lax',
      'Max-Age=0',
      'Path=/'
    ].filter(Boolean).join('; ')

    res.setHeader('Set-Cookie', cookieValue)

    return res.json({ 
      success: true,
      message: 'Session cleared successfully' 
    })

  } catch (error) {
    console.error('[CART_SESSION] DELETE error:', error)
    return res.status(500).json({ 
      error: 'Failed to clear session',
      message: error instanceof Error ? error.message : 'Unknown error'
    })
  }
}

// PUT - Rotate session (for long-lived sessions)
export async function PUT(req: MedusaRequest, res: MedusaResponse) {
  try {
    const cookies = parseCookies(req.headers.cookie as string | undefined)
    const oldSessionToken = cookies[CART_SESSION_COOKIE]

    if (!oldSessionToken) {
      return res.status(400).json({ 
        error: 'No active session to rotate' 
      })
    }

    const result = await SessionManager.rotateSession(req, oldSessionToken)

    if (!result) {
      return res.status(400).json({ 
        error: 'Failed to rotate session - session invalid' 
      })
    }

    // Set new session cookie
    const isProduction = process.env.NODE_ENV === 'production'
    const cookieValue = [
      `${CART_SESSION_COOKIE}=${result.token}`,
      'HttpOnly',
      isProduction ? 'Secure' : '',
      'SameSite=Lax',
      `Max-Age=${CART_SESSION_TTL}`,
      'Path=/'
    ].filter(Boolean).join('; ')

    res.setHeader('Set-Cookie', cookieValue)

    return res.json({ 
      success: true,
      sessionId: result.session.sessionId,
      cartId: result.session.cartId,
      rotationCount: result.session.rotationCount,
      message: 'Session rotated successfully' 
    })

  } catch (error) {
    console.error('[CART_SESSION] PUT (rotate) error:', error)
    return res.status(500).json({ 
      error: 'Failed to rotate session',
      message: error instanceof Error ? error.message : 'Unknown error'
    })
  }
}

import { defineMiddlewares } from "@medusajs/framework/http"
import type { MedusaRequest, MedusaResponse, MedusaNextFunction } from "@medusajs/framework/http"
import { timingSafeEqual } from "crypto"
import { extractBearerToken, verifyAccessToken } from "../utils/jwt"
import { validateCartOwnership } from "./middlewares/cartOwnership"

/** Constant-time comparison to prevent timing attacks on secret values */
function safeCompare(a: string, b: string): boolean {
  if (!a || !b || a.length !== b.length) return false
  return timingSafeEqual(Buffer.from(a), Buffer.from(b))
}

// Explicit CORS + diagnostics for Store routes. This guarantees that
// custom headers like `x-publishable-api-key` are allowed and that
// all OPTIONS preflights are answered consistently, which helps avoid
// browser "No 'Access-Control-Allow-Origin' header" errors when a
// guard rejects the request early.

const allowedOrigins = (process.env.STORE_CORS || "http://localhost:3000,http://127.0.0.1:3000").split(",")

const allowedHeaders = (
  process.env.STORE_ALLOWED_HEADERS ||
  "Content-Type, Accept, Authorization, X-Requested-With, x-publishable-api-key"
)

async function corsAndDiagnostics(
  req: MedusaRequest,
  res: MedusaResponse,
  next: MedusaNextFunction
) {
  const origin = req.headers.origin as string | undefined
  if (origin && allowedOrigins.includes(origin)) {
    res.setHeader("Access-Control-Allow-Origin", origin)
  }
  res.setHeader("Vary", "Origin")
  res.setHeader("Access-Control-Allow-Credentials", "true")
  res.setHeader(
    "Access-Control-Allow-Methods",
    "GET,POST,PUT,PATCH,DELETE,OPTIONS"
  )
  res.setHeader("Access-Control-Allow-Headers", allowedHeaders + ",Cookie")

  // Basic diagnostics for tricky requests (visible in backend logs)
  if (req.path?.includes("/store/carts/") && req.path?.includes("/payment-sessions")) {
    // Log enough to trace, but avoid dumping PII
    console.log("[CORS][Store]", {
      method: req.method,
      path: req.path,
      origin,
      requestHeaders: req.headers["access-control-request-headers"],
      hasPublishableKey: Boolean(req.headers["x-publishable-api-key"]),
    })
  }

  // Short-circuit preflight
  if (req.method === "OPTIONS") {
    return res.status(204).end()
  }

  next()
}

async function authGuard(
  req: MedusaRequest,
  res: MedusaResponse,
  next: MedusaNextFunction
) {
  try {
    // Allow internal server-to-server calls (e.g. payment capture from storefront server)
    const internalSecret = req.headers['x-internal-call'] as string | undefined
    if (internalSecret && process.env.INTERNAL_API_SECRET && safeCompare(internalSecret, process.env.INTERNAL_API_SECRET)) {
      return next()
    }

    const token = extractBearerToken(req.headers.authorization as string | undefined)
    if (!token) {
      return res.status(401).json({ message: "Missing bearer token" })
    }

    const claims = await verifyAccessToken(token, req.scope)

      // Attach identity to request context for downstream usage
      ; (req as any).customer_id = claims.sub
      ; (req as any).auth = { customer_id: claims.sub, claims }
    try {
      console.log('[authGuard] token valid', { sub: claims.sub, mfaComplete: claims.mfaComplete, purpose: claims.purpose })
    } catch { }

    if (claims.mfaComplete === false) {
      return res.status(403).json({ message: "MFA required" })
    }

    return next()
  } catch (e) {
    return res.status(401).json({ message: "Invalid or expired token" })
  }
}



// M9: Simple in-memory rate limiter for payment-critical endpoints
const rateLimitStore = new Map<string, { count: number; resetAt: number }>()
const RATE_LIMIT_WINDOW = 60_000 // 1 minute
const RATE_LIMIT_MAX = 10 // max requests per window per IP

function rateLimit(
  req: MedusaRequest,
  res: MedusaResponse,
  next: MedusaNextFunction
) {
  // Use socket IP directly to prevent spoofing via X-Forwarded-For header
  const ip = req.socket?.remoteAddress || "unknown"
  const key = `${ip}:${req.path}`
  const now = Date.now()

  const entry = rateLimitStore.get(key)
  if (!entry || now > entry.resetAt) {
    rateLimitStore.set(key, { count: 1, resetAt: now + RATE_LIMIT_WINDOW })
    return next()
  }

  entry.count++
  if (entry.count > RATE_LIMIT_MAX) {
    res.setHeader("Retry-After", String(Math.ceil((entry.resetAt - now) / 1000)))
    return res.status(429).json({ message: "Too many requests" })
  }

  return next()
}

// Cleanup stale entries every 5 minutes
setInterval(() => {
  const now = Date.now()
  for (const [key, val] of rateLimitStore) {
    if (now > val.resetAt) rateLimitStore.delete(key)
  }
}, 300_000)

export default defineMiddlewares({
  routes: [
    {
      matcher: "/store/*",
      middlewares: [corsAndDiagnostics],
    },
    {
      // Enforce elevated session (mfaComplete=true) on customer profile endpoints
      matcher: "/store/customers*",
      middlewares: [authGuard],
    },
    {
      // Enforce elevated session (mfaComplete=true) on custom customer UPDATE endpoint only
      // Find-or-create route will handle auth internally to allow Postman testing via admin token
      matcher: "/store/custom/customer/update*",
      middlewares: [authGuard],
    },
    {
      // Enforce elevated session (mfaComplete=true) on address book endpoints
      matcher: "/store/addresses*",
      middlewares: [authGuard],
    },
    {
      // Only authenticated customers can submit or edit reviews; GET is public
      matcher: "/store/custom/reviews*",
      method: ["POST", "PUT"],
      middlewares: [authGuard],
    },
    {
      // Wishlist endpoints require authentication + rate limiting
      matcher: "/store/custom/wishlist*",
      middlewares: [rateLimit, authGuard],
    },
    {
      // SECURITY FIX C4: Payment capture must require authentication
      // SECURITY FIX M9: Rate limit payment capture
      matcher: "/store/payments/*",
      method: ["POST"],
      middlewares: [rateLimit, authGuard],
    },
    {
      // SECURITY FIX H7: Custom order routes must require authentication at middleware level
      // SECURITY FIX M9: Rate limit order cancel/refund
      matcher: "/store/custom/orders*",
      middlewares: [rateLimit, authGuard],
    },
    {
      // Validate cart ownership for adding items to cart
      matcher: "/store/carts/:id/line-items",
      method: ["POST"],
      middlewares: [validateCartOwnership],
    },
    {
      // Validate cart ownership for updating/removing line items
      matcher: "/store/carts/:id/line-items/:lineItemId",
      method: ["POST", "DELETE"],
      middlewares: [validateCartOwnership],
    },
    {
      // Validate cart ownership for updating cart (addresses, shipping, etc.)
      matcher: "/store/carts/:id",
      method: ["POST"],
      middlewares: [validateCartOwnership],
    },
  ],
})

