/**
 * Enhanced Session Manager Service
 * 
 * Addresses Security Audit Issue #9: Session Management Weaknesses
 * 
 * Features:
 * - Cryptographically secure session tokens (crypto.randomBytes)
 * - Session expiration with configurable TTL
 * - Idle timeout detection (auto-expire inactive sessions)
 * - Automatic session rotation for long-lived sessions
 * - Device fingerprinting with validation
 * - IP address tracking and suspicious location detection
 * - Security logging for audit trails
 */

import crypto from 'crypto'
import type { MedusaRequest } from '@medusajs/framework/http'
import { kvGet, kvSet, kvDel } from '../utils/kv'

// Configuration constants
const SESSION_TTL = 86400 * 7 // 7 days in seconds
const IDLE_TIMEOUT = 60 * 60 * 1000 // 1 hour in milliseconds
const ROTATION_INTERVAL = 6 * 60 * 60 * 1000 // 6 hours in milliseconds
const SESSION_KEY_PREFIX = 'cart:session:'
const ROTATION_FLAG_PREFIX = 'session:needs_rotation:'

export interface CartSession {
  sessionId: string
  cartId: string
  userId?: string
  createdAt: number
  lastAccessedAt: number
  expiresAt: number
  ipAddress: string
  userAgent: string
  fingerprint: string
  rotationCount: number
}

export interface SessionValidationResult {
  valid: boolean
  session?: CartSession
  reason?: 'not_found' | 'expired' | 'idle_timeout' | 'fingerprint_mismatch' | 'rotation_required'
  requiresRotation?: boolean
}

export class SessionManager {
  /**
   * Generate a cryptographically secure session token
   */
  private static generateSessionToken(): string {
    return crypto.randomBytes(32).toString('hex')
  }

  /**
   * Generate device fingerprint from request headers
   * Uses SHA-256 hash of multiple browser signals
   */
  private static generateFingerprint(req: MedusaRequest): string {
    const userAgent = req.headers['user-agent'] || ''
    const acceptLanguage = req.headers['accept-language'] || ''
    const acceptEncoding = req.headers['accept-encoding'] || ''
    const dnt = req.headers['dnt'] || ''

    // Combine multiple signals for better uniqueness
    const fingerprintData = `${userAgent}|${acceptLanguage}|${acceptEncoding}|${dnt}`

    return crypto
      .createHash('sha256')
      .update(fingerprintData)
      .digest('hex')
      .substring(0, 24)
  }

  /**
   * Extract client IP address from request
   * Handles proxies and load balancers
   */
  private static getClientIp(req: MedusaRequest): string {
    // Check for forwarded IP from proxies
    const forwarded = req.headers['x-forwarded-for']
    if (typeof forwarded === 'string') {
      return forwarded.split(',')[0].trim()
    }

    const realIp = req.headers['x-real-ip']
    if (typeof realIp === 'string') {
      return realIp
    }

    // Fallback to direct connection IP
    return req.socket?.remoteAddress || 'unknown'
  }

  /**
   * Create a new session
   */
  static async createSession(
    req: MedusaRequest,
    cartId: string,
    userId?: string
  ): Promise<{ session: CartSession; token: string }> {
    const sessionToken = this.generateSessionToken()
    const now = Date.now()

    const session: CartSession = {
      sessionId: sessionToken,
      cartId,
      userId,
      createdAt: now,
      lastAccessedAt: now,
      expiresAt: now + (SESSION_TTL * 1000),
      ipAddress: this.getClientIp(req),
      userAgent: req.headers['user-agent'] || '',
      fingerprint: this.generateFingerprint(req),
      rotationCount: 0
    }

    // Store in KV with TTL
    await kvSet(
      `${SESSION_KEY_PREFIX}${sessionToken}`,
      session,
      SESSION_TTL
    )

    console.log('[SESSION_MANAGER] Session created', {
      sessionId: sessionToken.substring(0, 12) + '...',
      cartId,
      userId: userId ? userId.substring(0, 8) + '...' : 'guest',
      ipAddress: session.ipAddress,
      expiresAt: new Date(session.expiresAt).toISOString()
    })

    return { session, token: sessionToken }
  }

  /**
   * Validate an existing session
   * Checks expiration, idle timeout, and fingerprint
   */
  static async validateSession(
    req: MedusaRequest,
    sessionToken: string
  ): Promise<SessionValidationResult> {
    // Retrieve session from KV
    const session = await kvGet<CartSession>(`${SESSION_KEY_PREFIX}${sessionToken}`)

    if (!session) {
      return { 
        valid: false, 
        reason: 'not_found'
      }
    }

    const now = Date.now()

    // Check if session has expired
    if (now > session.expiresAt) {
      await this.deleteSession(sessionToken)
      return { 
        valid: false, 
        reason: 'expired'
      }
    }

    // Check idle timeout (1 hour of inactivity)
    if (now - session.lastAccessedAt > IDLE_TIMEOUT) {
      await this.deleteSession(sessionToken)

      console.warn('[SESSION_MANAGER] Session expired due to inactivity', {
        sessionId: sessionToken.substring(0, 12) + '...',
        lastAccessed: new Date(session.lastAccessedAt).toISOString(),
        idleMinutes: Math.round((now - session.lastAccessedAt) / 60000)
      })

      return { 
        valid: false, 
        reason: 'idle_timeout'
      }
    }

    // Validate device fingerprint (detect session hijacking)
    const currentFingerprint = this.generateFingerprint(req)
    if (currentFingerprint !== session.fingerprint) {
      // Log suspicious activity but don't immediately invalidate
      // (fingerprint can change legitimately, e.g., browser updates)
      console.warn('[SESSION_MANAGER] Fingerprint mismatch detected', {
        sessionId: sessionToken.substring(0, 12) + '...',
        expectedFingerprint: session.fingerprint,
        actualFingerprint: currentFingerprint,
        ipAddress: this.getClientIp(req),
        sessionIpAddress: session.ipAddress
      })

      // Strict mode: invalidate session on fingerprint mismatch
      // Uncomment if you want stricter security:
      // return { valid: false, reason: 'fingerprint_mismatch' }
    }

    // Check if session needs rotation (6 hours old)
    const sessionAge = now - session.createdAt
    if (sessionAge > ROTATION_INTERVAL) {
      return {
        valid: true,
        session,
        requiresRotation: true,
        reason: 'rotation_required'
      }
    }

    // Update last accessed time
    session.lastAccessedAt = now
    await kvSet(
      `${SESSION_KEY_PREFIX}${sessionToken}`,
      session,
      SESSION_TTL
    )

    return { 
      valid: true, 
      session 
    }
  }

  /**
   * Rotate session (create new token, preserve data)
   * Used for long-lived sessions to minimize hijacking window
   */
  static async rotateSession(
    req: MedusaRequest,
    oldSessionToken: string
  ): Promise<{ session: CartSession; token: string } | null> {
    const validation = await this.validateSession(req, oldSessionToken)

    if (!validation.valid || !validation.session) {
      return null
    }

    // Create new session with same data
    const newSessionToken = this.generateSessionToken()
    const now = Date.now()

    const newSession: CartSession = {
      ...validation.session,
      sessionId: newSessionToken,
      lastAccessedAt: now,
      expiresAt: now + (SESSION_TTL * 1000),
      fingerprint: this.generateFingerprint(req),
      rotationCount: validation.session.rotationCount + 1
    }

    // Store new session
    await kvSet(
      `${SESSION_KEY_PREFIX}${newSessionToken}`,
      newSession,
      SESSION_TTL
    )

    // Delete old session
    await this.deleteSession(oldSessionToken)

    console.log('[SESSION_MANAGER] Session rotated', {
      oldSessionId: oldSessionToken.substring(0, 12) + '...',
      newSessionId: newSessionToken.substring(0, 12) + '...',
      rotationCount: newSession.rotationCount,
      cartId: newSession.cartId
    })

    return { session: newSession, token: newSessionToken }
  }

  /**
   * Update session with new cart ID or user ID
   */
  static async updateSession(
    sessionToken: string,
    updates: Partial<Pick<CartSession, 'cartId' | 'userId'>>
  ): Promise<boolean> {
    const session = await kvGet<CartSession>(`${SESSION_KEY_PREFIX}${sessionToken}`)

    if (!session) {
      return false
    }

    const updatedSession = {
      ...session,
      ...updates,
      lastAccessedAt: Date.now()
    }

    await kvSet(
      `${SESSION_KEY_PREFIX}${sessionToken}`,
      updatedSession,
      SESSION_TTL
    )

    return true
  }

  /**
   * Delete a session
   */
  static async deleteSession(sessionToken: string): Promise<void> {
    await kvDel(`${SESSION_KEY_PREFIX}${sessionToken}`)
    await kvDel(`${ROTATION_FLAG_PREFIX}${sessionToken}`)
  }

  /**
   * Detect suspicious location changes
   * Simplified version - in production, use a geolocation service
   */
  static async detectSuspiciousLocation(
    session: CartSession,
    currentIp: string
  ): Promise<{ suspicious: boolean; reason?: string }> {
    // If same IP, no issue
    if (session.ipAddress === currentIp) {
      return { suspicious: false }
    }

    // If IP changed within a short time (< 5 minutes), potentially suspicious
    const timeSinceCreation = Date.now() - session.createdAt
    if (timeSinceCreation < 5 * 60 * 1000) {
      console.warn('[SESSION_MANAGER] Rapid IP change detected', {
        sessionId: session.sessionId.substring(0, 12) + '...',
        originalIp: session.ipAddress,
        currentIp,
        minutesElapsed: Math.round(timeSinceCreation / 60000)
      })

      return {
        suspicious: true,
        reason: 'rapid_ip_change'
      }
    }

    // In production, you would:
    // 1. Get geolocation for both IPs
    // 2. Calculate distance
    // 3. Check if impossible travel (e.g., 1000km in 10 minutes)
    // 4. Flag different countries

    return { suspicious: false }
  }

  /**
   * Cleanup expired sessions (cron job)
   */
  static async cleanupExpiredSessions(): Promise<number> {
    // Note: This is a placeholder
    // In production, implement a proper cleanup mechanism
    // KV store with TTL handles this automatically
    console.log('[SESSION_MANAGER] Cleanup executed (TTL-based auto-expiry active)')
    return 0
  }
}

/**
 * Distributed Lock Service
 * 
 * Provides atomic distributed locking to prevent race conditions
 * in order completion and other critical operations.
 * 
 * Uses Redis SET NX (set if not exists) for atomic lock acquisition.
 */

import { kvGet, kvDel, kvSetNX } from './kv'
import { kvSetNXAtomic } from './kvHybrid'
import { randomUUID } from 'crypto'

export interface Lock {
  resource: string
  token: string
  expiresAt: number
}

export interface LockAcquisitionResult {
  success: boolean
  lock?: Lock
  error?: string
}

// Note: Cloudflare KV requires minimum TTL of 60 seconds
const DEFAULT_LOCK_TTL = 60 // 60 seconds (minimum for Cloudflare KV)
const DEFAULT_RETRY_ATTEMPTS = 0 // Don't retry by default
const DEFAULT_RETRY_DELAY = 100 // 100ms between retries

/**
 * Acquires a distributed lock on a resource
 * 
 * @param resource - The resource identifier to lock (e.g., "cart:complete:cart_123")
 * @param ttlSeconds - Lock expiration time in seconds (default: 30)
 * @param retryAttempts - Number of times to retry if lock is held (default: 0)
 * @param retryDelayMs - Delay between retry attempts in milliseconds (default: 100)
 * @returns Lock object if acquired, null if failed
 */
export async function acquireDistributedLock(
  resource: string,
  ttlSeconds: number = DEFAULT_LOCK_TTL,
  retryAttempts: number = DEFAULT_RETRY_ATTEMPTS,
  retryDelayMs: number = DEFAULT_RETRY_DELAY
): Promise<LockAcquisitionResult> {
  const lockKey = `lock:${resource}`

  // Generate unique token for this lock to prevent releasing someone else's lock
  const token = randomUUID()

  const lockData = {
    token,
    acquiredAt: Date.now(),
    expiresAt: Date.now() + ttlSeconds * 1000,
    resource,
  }

  let attempts = 0

  while (attempts <= retryAttempts) {
    try {
      // Atomic SET NX operation - only sets if key doesn't exist
      // Store as object (KV handles JSON serialization)
      const acquired = await kvSetNXAtomic(lockKey, lockData, ttlSeconds)

      if (acquired) {
        return {
          success: true,
          lock: {
            resource,
            token,
            expiresAt: lockData.expiresAt,
          },
        }
      }

      // Lock is held by someone else
      if (attempts < retryAttempts) {
        // Wait before retrying
        await new Promise(resolve => setTimeout(resolve, retryDelayMs))
        attempts++
        continue
      }

      // Max retries reached
      return {
        success: false,
        error: 'Lock is held by another process',
      }

    } catch (error) {
      console.error('[DISTRIBUTED_LOCK][acquire][error]', {
        resource,
        attempt: attempts + 1,
        error: String(error),
      })

      return {
        success: false,
        error: `Failed to acquire lock: ${String(error)}`,
      }
    }
  }

  return {
    success: false,
    error: 'Failed to acquire lock after retries',
  }
}

/**
 * Releases a distributed lock
 * Only releases if the provided token matches the lock owner
 * 
 * @param lock - The lock object to release
 * @returns true if released, false if lock was already expired or owned by someone else
 */
export async function releaseDistributedLock(lock: Lock): Promise<boolean> {
  const lockKey = `lock:${lock.resource}`

  try {
    // Verify lock ownership before deleting
    // KV returns already-parsed object, not string
    const currentLock = await kvGet<{ token: string; acquiredAt: number; expiresAt: number; resource: string }>(lockKey)

    if (!currentLock) {
      // Lock already expired or doesn't exist
      console.warn('[DISTRIBUTED_LOCK][release][already_expired]', {
        resource: lock.resource,
      })
      return false
    }

    // Only delete if token matches (prevents releasing someone else's lock)
    if (currentLock.token !== lock.token) {
      console.warn('[DISTRIBUTED_LOCK][release][token_mismatch]', {
        resource: lock.resource,
        expectedToken: lock.token,
        currentToken: currentLock.token,
      })
      return false
    }

    // Delete the lock
    await kvDel(lockKey)

    console.log('[DISTRIBUTED_LOCK][release][success]', {
      resource: lock.resource,
    })

    return true

  } catch (error) {
    console.error('[DISTRIBUTED_LOCK][release][error]', {
      resource: lock.resource,
      error: String(error),
    })
    return false
  }
}

/**
 * Checks if a lock is currently held for a resource
 * 
 * @param resource - The resource identifier
 * @returns true if lock exists and hasn't expired
 */
export async function isLockHeld(resource: string): Promise<boolean> {
  const lockKey = `lock:${resource}`

  try {
    // KV returns already-parsed object
    const lock = await kvGet<{ token: string; acquiredAt: number; expiresAt: number; resource: string }>(lockKey)

    if (!lock) return false

    // Check if lock has expired (defensive check in case TTL didn't work)
    if (lock.expiresAt && Date.now() > lock.expiresAt) {
      // Clean up expired lock
      await kvDel(lockKey)
      return false
    }

    return true

  } catch (error) {
    console.error('[DISTRIBUTED_LOCK][isLockHeld][error]', {
      resource,
      error: String(error),
    })
    return false
  }
}

/**
 * Extends the TTL of an existing lock
 * Useful for long-running operations that need to keep the lock longer
 * 
 * @param lock - The lock to extend
 * @param additionalSeconds - Additional seconds to add to TTL
 * @returns true if extended successfully
 */
export async function extendLock(lock: Lock, additionalSeconds: number): Promise<boolean> {
  const lockKey = `lock:${lock.resource}`

  try {
    // KV returns already-parsed object
    const currentLock = await kvGet<{ token: string; acquiredAt: number; expiresAt: number; resource: string }>(lockKey)

    if (!currentLock) {
      console.warn('[DISTRIBUTED_LOCK][extend][not_found]', {
        resource: lock.resource,
      })
      return false
    }

    // Verify ownership
    if (currentLock.token !== lock.token) {
      console.warn('[DISTRIBUTED_LOCK][extend][token_mismatch]', {
        resource: lock.resource,
      })
      return false
    }

    // Update expiration time
    const newExpiresAt = Date.now() + additionalSeconds * 1000
    currentLock.expiresAt = newExpiresAt

    // Re-set with new TTL (store as object, KV handles serialization)
    await kvDel(lockKey)
    await kvSetNX(lockKey, currentLock, additionalSeconds)

    lock.expiresAt = newExpiresAt

    return true

  } catch (error) {
    console.error('[DISTRIBUTED_LOCK][extend][error]', {
      resource: lock.resource,
      error: String(error),
    })
    return false
  }
}

// Upstash REST config
const KV_URL = process.env.KV_REST_API_URL
const KV_TOKEN = process.env.KV_REST_API_TOKEN

// Cloudflare KV config
const CF_ACCOUNT_ID = process.env.CF_KV_ACCOUNT_ID
const CF_NAMESPACE_ID = process.env.CF_KV_NAMESPACE_ID
const CF_API_TOKEN = process.env.CF_KV_API_TOKEN

function useCloudflare(): boolean {
  return Boolean(CF_ACCOUNT_ID && CF_NAMESPACE_ID && CF_API_TOKEN)
}

export function kvProvider(): 'cloudflare' | 'upstash' | 'none' {
  if (useCloudflare()) return 'cloudflare'
  if (KV_URL && KV_TOKEN) return 'upstash'
  return 'none'
}

// Log KV provider on module load (server-side only)
if (typeof window === 'undefined') {
  const provider = kvProvider()
  console.log(`[KV] Provider: ${provider}`, {
    cloudflare: useCloudflare() ? 'configured' : 'not configured',
    upstash: (KV_URL && KV_TOKEN) ? 'configured' : 'not configured',
  })
  if (provider === 'none') {
    console.warn('[KV] WARNING: No KV provider configured. Magic link verification will NOT work!')
  }
}

export async function kvSet(key: string, value: unknown, ttlSeconds?: number): Promise<void> {
  if (useCloudflare()) {
    const base = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/storage/kv/namespaces/${CF_NAMESPACE_ID}/values/${encodeURIComponent(key)}`
    const url = ttlSeconds ? `${base}?expiration_ttl=${ttlSeconds}` : base
    const res = await fetch(url, {
      method: 'PUT',
      headers: {
        Authorization: `Bearer ${CF_API_TOKEN}`,
        'Content-Type': 'text/plain',
      },
      body: typeof value === 'string' ? value : JSON.stringify(value),
    })
    if (!res.ok) throw new Error(`CF KV set failed ${res.status}`)
    return
  }

  if (!KV_URL || !KV_TOKEN) return
  const url = `${KV_URL}/set/${encodeURIComponent(key)}`
  const res = await fetch(url, {
    method: 'POST',
    headers: { Authorization: `Bearer ${KV_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ value, nx: false, ex: ttlSeconds }),
  })
  if (!res.ok) throw new Error(`KV set failed ${res.status}`)
}

/**
 * Atomic SET if Not eXists (NX) operation for distributed locking
 * Returns true if key was set, false if key already exists
 * Throws error if no KV store is configured
 * 
 * Note: Cloudflare KV requires minimum TTL of 60 seconds
 */
export async function kvSetNX(key: string, value: unknown, ttlSeconds?: number): Promise<boolean> {
  if (useCloudflare()) {
    // Cloudflare KV doesn't support atomic NX, so we simulate with get-then-set
    // This is NOT truly atomic but better than nothing for Cloudflare
    const existing = await kvGet(key)
    if (existing !== null) return false

    // Cloudflare KV requires minimum TTL of 60 seconds
    const actualTTL = ttlSeconds && ttlSeconds >= 60 ? ttlSeconds : 60

    const base = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/storage/kv/namespaces/${CF_NAMESPACE_ID}/values/${encodeURIComponent(key)}`
    const url = `${base}?expiration_ttl=${actualTTL}`
    const res = await fetch(url, {
      method: 'PUT',
      headers: {
        Authorization: `Bearer ${CF_API_TOKEN}`,
        'Content-Type': 'text/plain',
      },
      body: typeof value === 'string' ? value : JSON.stringify(value),
    })
    if (!res.ok) {
      const errorText = await res.text().catch(() => 'Unknown error')
      throw new Error(`CF KV setNX failed ${res.status}: ${errorText}`)
    }
    return true
  }

  if (KV_URL && KV_TOKEN) {
    // Upstash Redis supports atomic SET NX EX
    const url = `${KV_URL}/set/${encodeURIComponent(key)}`
    const body: any = { value, nx: true }
    if (ttlSeconds) body.ex = ttlSeconds

    const res = await fetch(url, {
      method: 'POST',
      headers: { Authorization: `Bearer ${KV_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    })

    if (!res.ok) {
      const errorText = await res.text().catch(() => 'Unknown error')
      throw new Error(`KV setNX failed ${res.status}: ${errorText}`)
    }

    const json = await res.json().catch(() => null)
    // Upstash returns { result: "OK" } on success, { result: null } if key exists
    return json?.result === 'OK'
  }

  // No KV store configured - critical error
  throw new Error('KV store not configured. Cannot acquire distributed lock. Set CF_KV_* or KV_REST_API_* environment variables.')
}

export async function kvGet<T = unknown>(key: string): Promise<T | null> {
  if (useCloudflare()) {
    const url = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/storage/kv/namespaces/${CF_NAMESPACE_ID}/values/${encodeURIComponent(key)}`
    const res = await fetch(url, { headers: { Authorization: `Bearer ${CF_API_TOKEN}` } })
    if (res.status === 404) return null
    if (!res.ok) throw new Error(`CF KV get failed ${res.status}`)
    const text = await res.text()
    try { return JSON.parse(text) as T } catch { return text as unknown as T }
  }

  if (!KV_URL || !KV_TOKEN) return null
  const url = `${KV_URL}/get/${encodeURIComponent(key)}`
  const res = await fetch(url, { headers: { Authorization: `Bearer ${KV_TOKEN}` } })
  if (res.status === 404) return null
  if (!res.ok) throw new Error(`KV get failed ${res.status}`)
  const json = await res.json().catch(() => null)
  return (json?.result ?? null) as T | null
}

export async function kvDel(key: string): Promise<void> {
  if (useCloudflare()) {
    const url = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/storage/kv/namespaces/${CF_NAMESPACE_ID}/values/${encodeURIComponent(key)}`
    const res = await fetch(url, { method: 'DELETE', headers: { Authorization: `Bearer ${CF_API_TOKEN}` } })
    if (!res.ok && res.status !== 404) throw new Error(`CF KV del failed ${res.status}`)
    return
  }

  if (!KV_URL || !KV_TOKEN) return
  const url = `${KV_URL}/del/${encodeURIComponent(key)}`
  const res = await fetch(url, { method: 'DELETE', headers: { Authorization: `Bearer ${KV_TOKEN}` } })
  if (!res.ok && res.status !== 404) throw new Error(`KV del failed ${res.status}`)
}

export async function kvIncr(key: string): Promise<number | null> {
  if (useCloudflare()) {
    // Non-atomic approximation: read, increment, write back
    const current = await kvGet<string | number | null>(key)
    const n = (typeof current === 'number' ? current : parseInt(String(current || '0'), 10)) || 0
    const next = n + 1
    await kvSet(key, String(next))
    return next
  }

  if (!KV_URL || !KV_TOKEN) return null
  const url = `${KV_URL}/incr/${encodeURIComponent(key)}`
  const res = await fetch(url, { method: 'POST', headers: { Authorization: `Bearer ${KV_TOKEN}` } })
  if (!res.ok) throw new Error(`KV incr failed ${res.status}`)
  const json = await res.json().catch(() => null)
  // Upstash returns { result: 1 }
  return (json as any)?.result ?? null
}

export async function kvExpire(key: string, ttlSeconds: number): Promise<void> {
  if (useCloudflare()) {
    const val = await kvGet<string>(key)
    if (val == null) return
    const base = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/storage/kv/namespaces/${CF_NAMESPACE_ID}/values/${encodeURIComponent(key)}`
    const url = `${base}?expiration_ttl=${ttlSeconds}`
    const res = await fetch(url, {
      method: 'PUT',
      headers: { Authorization: `Bearer ${CF_API_TOKEN}`, 'Content-Type': 'text/plain' },
      body: typeof val === 'string' ? val : JSON.stringify(val),
    })
    if (!res.ok) throw new Error(`CF KV expire failed ${res.status}`)
    return
  }

  if (!KV_URL || !KV_TOKEN) return
  const url = `${KV_URL}/expire/${encodeURIComponent(key)}/${ttlSeconds}`
  const res = await fetch(url, { method: 'POST', headers: { Authorization: `Bearer ${KV_TOKEN}` } })
  if (!res.ok) throw new Error(`KV expire failed ${res.status}`)
}

export async function kvListKeys(prefix = '', limit = 1000): Promise<string[]> {
  if (useCloudflare()) {
    const url = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/storage/kv/namespaces/${CF_NAMESPACE_ID}/keys?prefix=${encodeURIComponent(prefix)}&limit=${limit}`
    const res = await fetch(url, { headers: { Authorization: `Bearer ${CF_API_TOKEN}` } })
    if (!res.ok) throw new Error(`CF KV list failed ${res.status}`)
    const json = await res.json().catch(() => null) as any
    const result = Array.isArray(json?.result) ? json.result : []
    return result.map((k: any) => String(k?.name)).filter(Boolean)
  }
  // Upstash list not supported via this helper; return empty
  return []
}

